<template>
  <div style="width: 100%;height: 100%">
    <div class="node-start" :class="{ 'node-start--selected': isSelected }">
      <div class="bar" />
      <div class="body">
        <div class="icon-wrap">
          <PlayCircleOutlined class="icon" />
        </div>
        <div class="info">
                    <div class="name">{{ nodeData.label || '开始' }}</div>
          <div class="sub">流程起始节点 state: {{ nodeState }}</div>
        </div>
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref, onMounted, onUnmounted, inject } from 'vue'
import { PlayCircleOutlined } from '@ant-design/icons-vue'
import type { Node, Graph } from '@antv/x6'
import type { FlowNodeData } from '../types/flow.types'

const props     = defineProps<{ node: Node }>()
const getGraph  = inject<() => Graph>('getGraph')

const nodeData   = ref<FlowNodeData>(props.node.getData() ?? {})
const isSelected = ref(false)
const nodeState  = ref<string>(props.node.getProp('_state') || 'default')

const updateNodeData = () => {
  nodeData.value = props.node.getData() ?? {}
}

const updateNodeState = ({ key, current }: { key: string; current: any }) => {
  if (key === '_state') {
    nodeState.value = current || 'default'
  }
}

onMounted(() => {
  props.node.on('change:data', updateNodeData)
  props.node.on('change:*', updateNodeState)
  const graph = getGraph?.()
  if (graph) {
    graph.on('cell:selected',   ({ cell }) => { if (cell.id === props.node.id) isSelected.value = true  })
    graph.on('cell:unselected', ({ cell }) => { if (cell.id === props.node.id) isSelected.value = false })
  }
})

onUnmounted(() => {
  props.node.off('change:data', updateNodeData)
  props.node.off('change:*', updateNodeState)
})
</script>

<style scoped>
.node-start {
  width: 100%;
  height: 100%;
  background: #fff;
  border: 1.5px solid #e8e8e8;
  border-radius: 8px; overflow: hidden;
  box-shadow: 0 2px 8px rgba(0,0,0,.08);
  display: flex; flex-direction: column;
  user-select: none;
  transition: box-shadow 0.2s, border-color 0.2s;
}
.node-start:hover {
  border: 3px solid #52c41a;
  -background: #f1f5f1;
}
.node-start--selected {
  border: 3px solid #52c41a;
  box-shadow: 0 0 0 3px rgba(245,34,45,0.15), 0 2px 8px rgba(0,0,0,.08);
}
.node-start--selected {
  border-color: #52c41a;
  box-shadow: 0 0 0 3px rgba(82,196,26,0.15), 0 2px 8px rgba(0,0,0,.08);
}
.bar {
  height: 4px; flex-shrink: 0;
  background: linear-gradient(90deg, #52c41a 0%, #95de64 100%);
}
.body { flex: 1; display: flex; align-items: center; padding: 0 12px; gap: 10px; }
.icon-wrap {
  width: 32px; height: 32px; border-radius: 8px; flex-shrink: 0;
  background: rgba(82,196,26,0.1);
  display: flex; align-items: center; justify-content: center;
}
.icon { font-size: 16px; color: #52c41a; }
.info { overflow: hidden; flex: 1; }
.name { font-size: 13px; font-weight: 600; color: #262626; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.sub  { font-size: 11px; color: #8c8c8c; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; margin-top: 2px; }
</style>
