import type { CanvasConfig } from '../../../views/types/flow.types'

/**
 * 默认画布配置
 * 对应 X6 Graph 初始化选项，所有字段均可通过 FlowDesignerLayout 的 canvasConfig prop 覆盖。
 * 参考：https://x6.antv.antgroup.com/api/graph/graph
 */
export const DEFAULT_CANVAS_CONFIG: CanvasConfig = {

  // ─── 网格配置 ─────────────────────────────────────────────────────────────
  // 对应 X6 Graph 选项：grid
  // 参考：https://x6.antv.antgroup.com/api/graph/grid
  grid: {
    /** 是否显示网格。对应 grid.visible */
    visible: true,
    /**
     * 网格类型。对应 grid.type
     * - 'dot'  : 点状网格（默认）
     * - 'mesh' : 线状网格
     */
    type: 'dot',
    /** 网格单元尺寸（px），节点拖拽会按此值对齐（需开启 snapToGrid）。对应 grid.size */
    size: 20,
    /** 网格点/线的颜色。对应 grid.args[0].color */
    color: '#6b6b6b',
    /** 网格点/线的粗细（px）。对应 grid.args[0].thickness */
    thickness: 2,
  },

  // ─── 对齐配置 ─────────────────────────────────────────────────────────────
  // 对应 X6 插件：Snapline / graph.snapGrid
  // 参考：https://x6.antv.antgroup.com/api/graph/snapline
  align: {
    /**
     * 是否启用对齐线（Snapline）。
     * 拖拽节点时显示辅助对齐线，帮助节点与其他节点对齐。
     * 对应 Graph.use(Snapline, { enabled: true })
     */
    snaplineEnabled: true,
    /**
     * 是否将节点移动强制吸附到网格。
     * true: 节点只能落在网格整数格点上；false: 自由移动。
     * 对应 Graph 构造项 snapGrid: { size }
     */
    snapToGrid: false,
    /**
     * 对齐吸附半径（px）。
     * 节点拖拽时，距对齐线/网格在此范围内时自动吸附。
     * 对应 Snapline 插件的 tolerance 选项
     */
    snapRadius: 20,
  },

  // ─── 连线配置 ─────────────────────────────────────────────────────────────
  // 对应 X6 Graph 构造项：connecting
  // 参考：https://x6.antv.antgroup.com/api/graph/connecting
  connection: {
    /**
     * 路由算法，决定连线走向。对应 connecting.router
     * - 'manhattan' : 直角折线（自动绕障）
     * - 'metro'     : 地铁风格直角折线
     * - 'orth'      : 正交折线（不绕障）
     */
    router: 'metro',
    /**
     * 连接器类型，决定连线端点及弯角样式。对应 connecting.connector
     * - 'rounded'  : 圆角折线
     * - 'smooth'   : 平滑曲线（贝塞尔）
     * - 'normal'   : 直线段无特殊处理
     * - 'jumpover' : 交叉处绘制跳线弧（需 connector 支持）
     * 注意：'jumpover' 是 X6 内置 connector 名称，用于连线交叉跳过效果
     */
    connector: 'rounded',
    /**
     * 是否允许连接到画布空白处（不连到任何节点/端口）。对应 connecting.allowBlank
     * false: 连线必须连到有效节点，否则回弹取消
     */
    allowBlank: false,
    /**
     * 是否允许创建自环连线（起点和终点是同一节点）。对应 connecting.allowLoop
     * false: 禁止节点自身连接自身
     */
    allowLoop: false,
    /**
     * 是否允许两个节点之间存在多条连线。对应 connecting.allowMulti
     * false: 同一对节点只能有一条连线
     */
    allowMulti: false,
    /** 连线描边宽度（px）。对应 edge 默认样式 attrs/line/strokeWidth */
    strokeWidth: 2,
    /** 连线描边颜色。对应 edge 默认样式 attrs/line/stroke（default 状态灰色） */
    strokeColor: '#b0b8c4',
    /**
     * 连线交互层宽度（px）。
     * 用于增大连线的 hover/click 判定范围，视觉上不可见。
     * 对应 edge 默认样式 attrs/line/strokeWidth（用于交互检测）
     * 推荐值：15-30，越大越容易触发 hover
     */
    interactionWidth: 20,
    // 连线标签样式，在 GraphInitializer 中映射为 edge defaultLabel attrs
    label: {
      /** 标签背景色（SVG foreignObject 容器背景）*/
      backgroundColor: '#ffffff',
      /** 标签边框颜色（浅蓝色） */
      borderColor: '#cccccc',
      /** 标签边框宽度（px）*/
      borderWidth: 1,
      /** 标签文字颜色 */
      textColor: '#999999',
      /** 标签字号（px）*/
      fontSize: 12,
      /** 标签字重（CSS font-weight）*/
      fontWeight: 500,
      /**
       * 标签在连线上的位置比例，取值范围 0～1。
       * 0: 起点，0.5: 中点，1: 终点。对应 label.position.distance
       */
      position: 0.5,
      /** 标签内边距（px），paddingX/paddingY 未设置时的 fallback */
      padding: 4,
      /** 左右内边距（px），优先级高于 padding */
      paddingX: 6,
      /** 上下内边距（px），优先级高于 padding。设置较小值以补偿 SVG text bbox 含字体行距 */
      paddingY: 2,
      /** 背景矩形垂直方向微调（px），正值向下，用于补偿 SVG text baseline 上下不对称（ascender > descender） */
      offsetY: 1,
      /** 标签背景圆角（px）*/
      borderRadius: 4,
      /**
       * SVG 文字水平锚点。对应 label text-anchor 属性
       * - 'start'  : 左对齐
       * - 'middle' : 居中（默认）
       * - 'end'    : 右对齐
       */
      textAnchor: 'middle',
      /**
       * SVG 文字垂直锚点。对应 label dominant-baseline 等效属性
       * - 'top'    : 顶部对齐
       * - 'middle' : 垂直居中（默认）
       * - 'bottom' : 底部对齐
       */
      textVerticalAnchor: 'middle',
      /**
       * 标签鼠标事件穿透。对应 CSS pointer-events
       * 'none': 标签不捕获鼠标事件，点击穿透到连线本身
       */
      pointerEvents: 'auto',
    },
  },

  // ─── 交互配置 ─────────────────────────────────────────────────────────────
  // 参考：https://x6.antv.antgroup.com/api/graph/panning
  //       https://x6.antv.antgroup.com/api/graph/mousewheel
  //       https://x6.antv.antgroup.com/api/graph/selection
  interaction: {
    /**
     * 是否开启画布拖拽平移（按住空格或右键拖拽）。
     * 对应 Graph 构造项 panning: { enabled: true }
     */
    panning: false,
    /**
     * 是否开启鼠标滚轮缩放画布。
     * 对应 Graph 构造项 mousewheel: { enabled: true }
     */
    mousewheel: false,
    /**
     * 是否开启框选（Rubberband）。
     * 鼠标在画布空白区域拖拽，绘制矩形框选中范围内的所有节点/边。
     * 对应 Graph.use(Selection, { rubberband: true })
     */
    rubberband: true,
    /**
     * 是否允许多选（按住 Ctrl/Cmd 点击追加选中）。
     * 对应 Selection 插件 multiple 选项
     */
    multipleSelection: true,
    /**
     * 是否允许拖拽移动节点。
     * 对应 graph.options.interacting 中 nodeMovable 设为 true
     */
    movable: true,
    /**
     * 是否允许拖拽调整节点大小（显示 resize handle）。
     * 对应 Graph.use(Transform, { resizing: { enabled: true } })
     * 当前设为 false，节点尺寸固定
     */
    resizable: true,
  },

  // ─── 高亮配置 ─────────────────────────────────────────────────────────────
  // 高亮效果通过 X6 高亮器（Highlighter）实现，在 GraphInitializer 中注册。
  // 参考：https://x6.antv.antgroup.com/api/registry/highlighter
  highlight: {
    // 节点悬停高亮
    nodeHover: {
      /** 是否在节点悬停时高亮 */
      enabled: false,
      /** 高亮描边颜色 */
      strokeColor: '#1677ff',
      /** 高亮描边宽度（px）*/
      strokeWidth: 2,
      /** 是否附加阴影效果 */
      shadow: true,
    },
    // 节点选中高亮（当前由各节点组件自身 CSS 处理，此项保留供扩展）
    nodeSelected: {
      /** 是否在节点选中时通过高亮器添加外框 */
      enabled: false,
      strokeColor: '#1677ff',
      strokeWidth: 2.5,
      shadow: true,
    },
    // 连线悬停高亮
    edgeHover: {
      /** 是否在连线悬停时高亮 */
      enabled: true,
      strokeColor: '#1677ff',
      textColor: '#1677ff',
      strokeWidth: 2,
    },
    // 连线悬停重叠优化（hover 时降低重叠连线的透明度，高密度连线场景提升可读性）
    edgeHoverOverlap: {
      /** 是否启用重叠连线透明度优化 */
      enabled: true,
      /** 重叠连线的目标透明度（0-1） */
      opacity: 0.36,
      /** 透明度过渡动画时长（ms） */
      transitionDuration: 150,
      /** 当连线数量超过此值时自动禁用该功能（性能保护），0 或 undefined 表示不限制 */
      disableWhenEdgeCountExceeds: 100,
    },
    // 连线选中高亮（由 X6 Selection 插件自动触发）
    edgeSelected: {
      /** 是否在连线选中时高亮 */
      enabled: true,
      strokeColor: '#1677ff',
      textColor: '#1677ff',
      strokeWidth: 2,
    },
    // 端口默认样式（静止状态，节点注册时使用）
    portDefault: {
      /** 端口填充颜色 */
      fill: '#ffffff',
      /** 端口描边颜色 */
      stroke: '#1677ff',
      /** 端口圆半径（px）*/
      size: 4,
      /** 端口描边宽度（px）*/
      strokeWidth: 2,
    },
    // 端口悬停高亮（鼠标悬停在端口上时）
    portHover: {
      /** 是否在端口悬停时高亮 */
      enabled: true,
      /** 端口高亮描边颜色 */
      strokeColor: '#1677ff',
      /** 端口高亮填充颜色 */
      fillColor: '#1677ff',
      /** 端口描边宽度 */
      strokeWidth: 2,
      /** 端口高亮时的圆半径（px）*/
      size: 4,
    },
    // 磁铁吸附高亮（连线终点靠近端口、准备连接时）
    magnetAdsorbed: {
      /** 是否在磁铁吸附时高亮目标端口 */
      enabled: true,
      strokeColor: '#1677ff',
      strokeWidth: 6,
    },
    // 可用磁铁高亮（开始绘制连线时，标记所有可连接的端口）
    magnetAvailable: {
      /** 是否高亮显示当前可连接的端口 */
      enabled: true,
      /** 可连接端口的高亮颜色（绿色表示可用） #ff4d4f*/
      strokeColor: '#8c8c8c',
      //fillColor: '#0000fc',
      fillColor: '#8c8c8c',
      strokeWidth: 2,
    },
    // 节点悉停时出线流动高亮
    nodeHoverOutEdgeFlow: {
      /** 是否开启：鼠标悉停节点时，出线变为蓝色流动线 */
      enabled: true,
      /** 流动线颜色 */
      strokeColor: '#1677ff',
      /** 流动线宽度（px）*/
      strokeWidth: 2,
      /** 流动动画周期（s），值越小流动越快 */
      duration: 0.6,
      /** 当节点数量超过此值时自动禁用该功能（性能保护），0 或 undefined 表示不限制 */
      disableWhenNodeCountExceeds: 500,
      /** 当单个节点的出线数量超过此值时不启用流动动画（性能保护），0 或 undefined 表示不限制 */
      disableWhenOutEdgeCountExceeds: 10,
    },
  },

  // ─── 背景配置 ─────────────────────────────────────────────────────────────
  // 对应 X6 Graph 构造项：background
  // 参考：https://x6.antv.antgroup.com/api/graph/background
  background: {
    /** 画布背景颜色。对应 background.color */
    color: '#f5f5f5',
    // image?   : 背景图片 URL，对应 background.image
    // repeat?  : 背景图片平铺方式，'repeat' | 'no-repeat' | 'watermark'
    // opacity? : 背景图片透明度，取值 0～1
  },

  // ─── 小地图配置 ────────────────────────────────────────────────────────────
  // 对应 X6 插件：MiniMap
  // 参考：https://x6.antv.antgroup.com/api/graph/minimap
  minimap: {
    /** 是否启用小地图。对应 MiniMap 插件 enabled */
    enabled: true,
    /** 小地图容器宽度（px）*/
    width: 180,
    /** 小地图容器高度（px）*/
    height: 120,
    /** 小地图内边距（px），防止内容紧贴边缘 */
    padding: 10,
  },

  // ─── 历史记录（撤销/重做）配置 ────────────────────────────────────────────
  // 对应 X6 插件：History
  // 参考：https://x6.antv.antgroup.com/api/graph/history
  history: {
    /** 是否启用历史记录（撤销/重做）。对应 History 插件 enabled */
    enabled: true,
    /**
     * 历史栈最大条数。超出后自动丢弃最旧的记录。
     * 对应 History 插件 stackSize 选项
     */
    stackSize: 100,
    /**
     * 是否忽略节点/边「添加」操作，不计入历史。
     * 对应 History 插件 ignoreAdd 选项
     */
    ignoreAdd: false,
    /**
     * 是否忽略节点/边「删除」操作，不计入历史。
     * 对应 History 插件 ignoreRemove 选项
     */
    ignoreRemove: false,
    /**
     * 是否忽略节点/边「属性变更」操作，不计入历史。
     * 对应 History 插件 ignoreChange 选项
     * ⚠️ 必须为 false，由 beforeAddCommand 白名单精确控制入栈内容
     * 若设为 true，连线端点(source/target)的 change 也会被屏蔽，导致 redo 后位置错误
     */
    ignoreChange: false,
  },

  // ─── Tooltip 配置 ─────────────────────────────────────────────────────────
  // Tooltip 悬停提示样式配置
  tooltip: {
    /** 字体大小（px）*/
    fontSize: 13,
    /** 字体粗细 */
    fontWeight: 'bold' as const,
    /** 文字颜色 */
    color: '#ffffff',
    /** 背景颜色（带透明度的黑色）*/
    backgroundColor: 'rgba(0, 0, 0, 0.75)',
    /** 内边距 */
    padding: '6px 12px',
    /** 圆角（px）*/
    borderRadius: 4,
    /** 阴影 */
    boxShadow: '0 2px 8px rgba(0, 0, 0, 0.25)',
    /** 是否显示箭头 */
    arrowEnabled: true,
    /** 箭头颜色（与背景色一致）*/
    arrowColor: 'rgba(0, 0, 0, 0.75)',
    /** 箭头高度（px）*/
    arrowSize: 8,
    /** z-index 层级 */
    zIndex: 9999,
    /** 最大宽度（undefined 表示不限制）*/
    maxWidth: undefined,
    /** 文本换行方式（nowrap 保持单行）*/
    whiteSpace: 'nowrap' as const,
    /** 水平偏移量（px），正值向右，负值向左 */
    offsetX: 0,
    /** 垂直偏移量（px），正值向下，负值向上 */
    offsetY: 0,
  },
}
