<template>
  <div class="node-card" :class="{ 'node-card--selected': isSelected }">
    <div class="bar" />
    <div class="body">
      <div class="icon-wrap">
        <MailOutlined class="icon" />
      </div>
      <div class="info">
        <div class="name">{{ nodeData.label || '通知节点' }}</div>
        <div class="sub">{{ subText }}</div>
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref, computed, onMounted, onUnmounted, inject } from 'vue'
import { MailOutlined } from '@ant-design/icons-vue'
import type { Node, Graph } from '@antv/x6'
import type { FlowNodeData } from '../types/flow.types'

const props     = defineProps<{ node: Node }>()
const getGraph  = inject<() => Graph>('getGraph')

const nodeData   = ref<FlowNodeData>(props.node.getData() ?? {})
const isSelected = ref(false)

const updateNodeData = () => {
  nodeData.value = props.node.getData() ?? {}
}

onMounted(() => {
  props.node.on('change:data', updateNodeData)
  const graph = getGraph?.()
  if (graph) {
    graph.on('cell:selected',   ({ cell }) => { if (cell.id === props.node.id) isSelected.value = true  })
    graph.on('cell:unselected', ({ cell }) => { if (cell.id === props.node.id) isSelected.value = false })
  }
})

onUnmounted(() => {
  props.node.off('change:data', updateNodeData)
})

const subText = computed(() => {
  const methods = nodeData.value.notifyMethods ?? []
  const map: Record<string, string> = { message: '站内信', email: '邮件', sms: '短信' }
  return methods.length ? methods.map(k => map[k]).join(' · ') : '未配置通知方式'
})
</script>

<style scoped>
.node-card {
  width: 200px; height: 72px;
  background: #fff;
  border: 1.5px solid #e8e8e8;
  border-radius: 8px; overflow: hidden;
  box-shadow: 0 2px 8px rgba(0,0,0,.08);
  display: flex; flex-direction: column; user-select: none;
  transition: box-shadow 0.2s, border-color 0.2s;
}
.node-card:hover {
  border: 2.5px solid #8c8c8c;
}
.node-card--selected {
  border: 3px solid #8c8c8c;
  box-shadow: 0 0 0 3px rgba(140,140,140,0.18), 0 2px 8px rgba(0,0,0,.08);
}
.bar  {
  height: 4px; flex-shrink: 0;
  background: linear-gradient(90deg, #8c8c8c 0%, #bfbfbf 100%);
}
.body { flex: 1; display: flex; align-items: center; padding: 0 12px; gap: 10px; }
.icon-wrap {
  width: 32px; height: 32px; border-radius: 8px; flex-shrink: 0;
  background: rgba(140,140,140,0.1);
  display: flex; align-items: center; justify-content: center;
}
.icon { font-size: 16px; color: #8c8c8c; }
.info { overflow: hidden; }
.name { font-size: 13px; font-weight: 600; color: #262626; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.sub  { font-size: 11px; color: #8c8c8c; margin-top: 2px; }
</style>
