import { register } from '@antv/x6-vue-shape'
import { Graph, Shape } from '@antv/x6'
import type { Component } from 'vue'
import StartNode       from './StartNode.vue'
import EndNode         from './EndNode.vue'
import ApproverNode    from './ApproverNode.vue'
import CountersignNode from './CountersignNode.vue'
import OrSignNode      from './OrSignNode.vue'
import ConditionNode   from './ConditionNode.vue'
import ParallelNode    from './ParallelNode.vue'
import NotifyNode      from './NotifyNode.vue'
import { DEFAULT_CANVAS_CONFIG } from '../../components/FlowDesigner/core/defaultConfig'

// ─── 公共 Port 样式 ───────────────────────────────────────────────────────────

export interface PortDefaultConfig {
  fill: string
  stroke: string
  size: number
  strokeWidth: number
}

function makePortAttr(cfg: PortDefaultConfig) {
  return {
    circle: {
      r: cfg.size,
      magnet: true,
      stroke: cfg.stroke,
      strokeWidth: cfg.strokeWidth,
      fill: cfg.fill,
      style: { visibility: 'hidden' },
    },
  }
}

const DEFAULT_PORT_CONFIG: PortDefaultConfig = DEFAULT_CANVAS_CONFIG.highlight.portDefault

// 统一的4个双向锚点（上下左右均可入线和出线）
function makeFourWayPorts(cfg: PortDefaultConfig = DEFAULT_PORT_CONFIG) {
  const attr = makePortAttr(cfg)
  return {
    groups: {
      top:    { position: 'top',    attrs: attr },
      right:  { position: 'right',  attrs: attr },
      bottom: { position: 'bottom', attrs: attr },
      left:   { position: 'left',   attrs: attr },
    },
    items: [
      { group: 'top',    id: 'port-top'    },
      { group: 'right',  id: 'port-right'  },
      { group: 'bottom', id: 'port-bottom' },
      { group: 'left',   id: 'port-left'   },
    ],
  }
}

// ─── 注册所有节点 ─────────────────────────────────────────────────────────────
export function registerAllNodes(portConfig?: PortDefaultConfig) {
  const cfg = portConfig ?? DEFAULT_PORT_CONFIG
    // 开始节点
  register({
    shape: 'start-node',
    width: 200, height: 72,
    component: StartNode,
    ports: makeFourWayPorts(cfg),
  })

  // 结束节点
  register({
    shape: 'end-node',
    width: 200, height: 72,
    component: EndNode,
    ports: makeFourWayPorts(cfg),
  })

  // 审批人节点
  register({
    shape: 'approver-node',
    width: 200, height: 72,
    component: ApproverNode,
    ports: makeFourWayPorts(cfg),
  })

  // 会签节点
  register({
    shape: 'countersign-node',
    width: 200, height: 72,
    component: CountersignNode,
    ports: makeFourWayPorts(cfg),
  })

  // 或签节点
  register({
    shape: 'orsign-node',
    width: 200, height: 72,
    component: OrSignNode,
    ports: makeFourWayPorts(cfg),
  })

  // 条件分支节点
  register({
    shape: 'condition-node',
    width: 100, height: 100,
    component: ConditionNode,
    ports: makeFourWayPorts(cfg),
  })

  // 并行分支节点
  register({
    shape: 'parallel-node',
    width: 200, height: 60,
    component: ParallelNode as Component,
    ports: makeFourWayPorts(cfg),
  })

    // 通知节点
  register({
    shape: 'notify-node',
    width: 200, height: 72,
    component: NotifyNode as Component,
    ports: makeFourWayPorts(cfg),
  })

    // 组节点
  // register({
  //   shape: 'group-node',
  //   width: 300,
  //   height: 200,
  //   component: GroupNode as Component,
  //   ports: {}, // 组节点不需要连接点
  // })

  // 通用 Vue 节点（不固定大小，由内容撑开）
  // register({
  //   shape: 'common-vue-node',
  //   width: 200,
  //   height: 72,
  //   component: CommonVueNode as Component,
  //   ports: makeFourWayPorts(cfg),
  // })

  // ✅ X6 原生节点（使用 SVG markup）
  Graph.registerNode('x6-node', {
    inherit: 'rect',
    width: 200,
    height: 72,
    markup: [
      {
        tagName: 'rect',
        selector: 'body',
      },
      {
        tagName: 'rect',
        selector: 'bar',
      },
      {
        tagName: 'rect',
        selector: 'iconBg',
      },
      {
        tagName: 'path',
        selector: 'icon',
      },
      {
        tagName: 'text',
        selector: 'label',
      },
      {
        tagName: 'text',
        selector: 'subLabel',
      },
    ],
    attrs: {
      body: {
        refWidth: '100%',
        refHeight: '100%',
        fill: '#ffffff',
        stroke: '#e8e8e8',
        strokeWidth: 1.5,
        rx: 8,
        ry: 8,
      },
      bar: {
        x: 0,
        y: 0,
        refWidth: '100%',
        height: 4,
        fill: {
          type: 'linearGradient',
          stops: [
            { offset: '0%', color: '#52c41a' },
            { offset: '100%', color: '#95de64' },
          ],
        },
        stroke: 'none',
      },
      iconBg: {
        x: 12,
        y: 20,
        width: 32,
        height: 32,
        rx: 8,
        ry: 8,
        fill: 'rgba(82, 196, 26, 0.1)',
        stroke: 'none',
      },
      icon: {
        // BlockOutlined 图标的 SVG path (从 Ant Design Icons 提取)
        d: 'M854.6 288.6L639.4 73.4c-6-6-14.1-9.4-22.6-9.4H192c-17.7 0-32 14.3-32 32v832c0 17.7 14.3 32 32 32h640c17.7 0 32-14.3 32-32V311.3c0-8.5-3.4-16.7-9.4-22.7zM790.2 326H602V137.8L790.2 326z m1.8 562H232V136h302v216a42 42 0 0 0 42 42h216v494z',
        fill: '#52c41a',
        // 将图标缩放到合适的大小并居中在iconBg中
        transform: 'translate(16, 24) scale(0.016, 0.016)',
      },
      label: {
        refX: 54,
        refY: 30,
        text: 'X6 节点',
        fontSize: 13,
        fontWeight: 600,
        fill: '#262626',
        textAnchor: 'start',
        fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto',
      },
      subLabel: {
        refX: 54,
        refY: 46,
        text: 'X6 通用节点',
        fontSize: 11,
        fill: '#8c8c8c',
        textAnchor: 'start',
        fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto',
      },
    },
    ports: {
      groups: {
        top:    { position: 'top',    attrs: { circle: { r: 6, magnet: true, stroke: '#52c41a', strokeWidth: 2, fill: '#fff', style: { visibility: 'hidden' } } } },
        right:  { position: 'right',  attrs: { circle: { r: 6, magnet: true, stroke: '#52c41a', strokeWidth: 2, fill: '#fff', style: { visibility: 'hidden' } } } },
        bottom: { position: 'bottom', attrs: { circle: { r: 6, magnet: true, stroke: '#52c41a', strokeWidth: 2, fill: '#fff', style: { visibility: 'hidden' } } } },
        left:   { position: 'left',   attrs: { circle: { r: 6, magnet: true, stroke: '#52c41a', strokeWidth: 2, fill: '#fff', style: { visibility: 'hidden' } } } },
      },
      items: [
        { group: 'top',    id: 'port-top'    },
        { group: 'right',  id: 'port-right'  },
        { group: 'bottom', id: 'port-bottom' },
        { group: 'left',   id: 'port-left'   },
      ],
    },
  })

  // ✅ HTML 节点
  Shape.HTML.register({
    shape: 'html-node',
    width: 200,
    height: 72,
    effect: ['data'],
    html(node) {
      //点击时通过setData改变data里面的状态如：state,节点内根据不同的state给不同的class
      //这判断到data变化会重新执行渲染，节点
      const data = node.getData() || {}
      const container = document.createElement('div')
      container.className = 'html-card-node'
      container.innerHTML = `
        <div class="node-card">
          <div class="bar"></div>
          <div class="body">
            <div class="icon-wrap">
              <svg width="16" height="16" viewBox="0 0 1024 1024" fill="#722ed1">
                <path d="M349.6 838.9c-13.5-13.3-13.7-35.2-.4-48.7L631.3 512 349.1 233.8c-13.3-13.5-13.1-35.4.4-48.7 13.5-13.3 35.3-13.1 48.7.4l306.9 302.3c13.1 13.1 13.1 34.4 0 47.4L398.2 838.5c-13.4 13.5-35.2 13.7-48.6.4z"/>
              </svg>
            </div>
            <div class="info">
              <div class="name">${data.label || 'HTML 节点'}</div>
              <div class="sub">${data.description || '自定义 HTML 内容'}</div>
            </div>
          </div>
        </div>
      `
      return container
    },
    ports: {
      groups: {
        top:    { position: 'top',    attrs: { circle: { r: 6, magnet: true, stroke: '#722ed1', strokeWidth: 2, fill: '#fff', style: { visibility: 'hidden' } } } },
        right:  { position: 'right',  attrs: { circle: { r: 6, magnet: true, stroke: '#722ed1', strokeWidth: 2, fill: '#fff', style: { visibility: 'hidden' } } } },
        bottom: { position: 'bottom', attrs: { circle: { r: 6, magnet: true, stroke: '#722ed1', strokeWidth: 2, fill: '#fff', style: { visibility: 'hidden' } } } },
        left:   { position: 'left',   attrs: { circle: { r: 6, magnet: true, stroke: '#722ed1', strokeWidth: 2, fill: '#fff', style: { visibility: 'hidden' } } } },
      },
      items: [
        { group: 'top',    id: 'port-top'    },
        { group: 'right',  id: 'port-right'  },
        { group: 'bottom', id: 'port-bottom' },
        { group: 'left',   id: 'port-left'   },
      ],
    },
  })
}













































































