<template>
  <div class="node-card" :class="{ 'node-card--selected': isSelected }">
    <div class="side-bar" />
    <div class="body">
      <div class="icon-wrap">
        <ApartmentOutlined class="icon" />
      </div>
      <span class="name">{{ nodeData.label || '并行分支' }}</span>
      <a-badge
        :count="nodeData.branchCount ?? 2"
        :number-style="{ backgroundColor: '#eb2f96', fontSize: '10px', minWidth: '16px', height: '16px', lineHeight: '16px' }"
        style="margin-left: auto"
      />
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref, computed, onMounted, onUnmounted, inject } from 'vue'
import { ApartmentOutlined } from '@ant-design/icons-vue'
import type { Node, Graph } from '@antv/x6'
import type { FlowNodeData } from '../types/flow.types'

const props     = defineProps<{ node: Node }>()
const getGraph  = inject<() => Graph>('getGraph')

const nodeData   = ref<FlowNodeData>(props.node.getData() ?? {})
const isSelected = ref(false)

const updateNodeData = () => {
  nodeData.value = props.node.getData() ?? {}
}

onMounted(() => {
  props.node.on('change:data', updateNodeData)
  const graph = getGraph?.()
  if (graph) {
    graph.on('cell:selected',   ({ cell }) => { if (cell.id === props.node.id) isSelected.value = true  })
    graph.on('cell:unselected', ({ cell }) => { if (cell.id === props.node.id) isSelected.value = false })
  }
})

onUnmounted(() => {
  props.node.off('change:data', updateNodeData)
})
</script>

<style scoped>
.node-card {
  width: 200px; height: 60px;
  background: #fff;
  border: 1.5px solid #e8e8e8;
  border-radius: 8px; overflow: hidden;
  box-shadow: 0 2px 8px rgba(0,0,0,.08);
  display: flex; position: relative; user-select: none;
  transition: box-shadow 0.2s, border-color 0.2s;
}
.node-card:hover {
  border: 3px solid #eb2f96;
}
.node-card--selected {
  border: 3px solid #eb2f96;
  background: #f8f8f8;
  box-shadow: 0 0 0 3px rgba(235,47,150,0.15), 0 2px 8px rgba(0,0,0,.08);
}
.side-bar {
  width: 4px; flex-shrink: 0;
  background: linear-gradient(180deg, #eb2f96 0%, #ff85c2 100%);
}
.body {
  flex: 1; display: flex; align-items: center;
  padding: 0 12px; gap: 8px;
}
.icon-wrap {
  width: 28px; height: 28px; border-radius: 7px; flex-shrink: 0;
  background: rgba(235,47,150,0.1);
  display: flex; align-items: center; justify-content: center;
}
.icon { font-size: 14px; color: #eb2f96; }
.name { font-size: 13px; font-weight: 600; color: #262626; }
</style>
