import { createRouter, createWebHashHistory } from 'vue-router'
import type { RouteRecordRaw } from 'vue-router'

const routes: RouteRecordRaw[] = [
  {
    path: '/',
    component: () => import('../views/FlowDesignerTest.vue'),
  },
  {
    path: '/guide',
    component: () => import('../views/guide/index.vue'),
  },
  {
    path: '/guide/introduction',
    component: () => import('../views/guide/chapters/01-introduction.vue'),
  },
  {
    path: '/guide/basic-usage',
    component: () => import('../views/guide/chapters/02-basic-usage.vue'),
  },
  {
    path: '/guide/flowdesigner-api',
    component: () => import('../views/guide/chapters/03-flowdesigner-api.vue'),
  },
  {
    path: '/guide/slots',
    component: () => import('../views/guide/chapters/04-slots.vue'),
  },
  {
    path: '/guide/permissions',
    component: () => import('../views/guide/chapters/05-permissions.vue'),
  },
  {
    path: '/guide/elements',
    component: () => import('../views/guide/chapters/06-elements.vue'),
  },
  {
    path: '/guide/shortcuts',
    component: () => import('../views/guide/chapters/07-shortcuts.vue'),
  },
  {
    path: '/guide/element-states',
    component: () => import('../views/guide/chapters/08-element-states.vue'),
  },
  {
    path: '/guide/advanced',
    component: () => import('../views/guide/chapters/09-advanced.vue'),
  },
  {
    path: '/guide/performance',
    component: () => import('../views/guide/chapters/10-performance.vue'),
  },
]

const router = createRouter({
  history: createWebHashHistory(),
  routes,
})

export default router
